patches.fixed_method:
public boolean hasSameMethod(Invocation candidate) { 
    Method m1 = invocation.getMethod();
    Method m2 = candidate.getMethod();
    return invocation.getMock().equals(candidate.getMock()) &&
           m1.getName().equals(m2.getName()) &&
           !invocation.isVerified() &&
           parameterTypesAreSame(m1.getParameterTypes(), m2.getParameterTypes()) &&
           argumentsAreSame(invocation.getArguments(), candidate.getArguments());
}

private boolean argumentsAreSame(Object[] args1, Object[] args2) {
    if (args1 == null || args2 == null) return args1 == args2;
    if (args1.length != args2.length) return false;
    for (int i = 0; i < args1.length; i++) {
        if (args1[i] == null ? args2[i] != null : !args1[i].equals(args2[i])) return false;
    }
    return true;
}

private boolean parameterTypesAreSame(Class<?>[] params1, Class<?>[] params2) {
    if (params1.length != params2.length) return false;
    for (int i = 0; i < params1.length; i++) {
        if (!params1[i].equals(params2[i])) return false;
    }
    return true;
}
